@lkraider 

Here's a worked example below. Many use cases. For instance, imagine storing a value that will become a redis key and needs to be transformed with other data for insertion but also consumed unaltered.

```
class CustomStringKeyType(BaseType):

    """A Unicode string field."""

    primitive_type = str
    native_type = str
    allow_casts = (int, bytes)

    MESSAGES = {
        'convert': "Couldn't interpret '{0}' as string.",
        'decode': "Invalid UTF-8 data.",
        'max_length': "String value is too long.",
        'min_length': "String value is too short.",
        'no_key': "missing key",
        'regex': "String value did not match validation regex.",
    }

    def __init__(self, regex=None, max_length=None, min_length=None, **kwargs):
        self.regex = re.compile(regex) if regex else None
        self.max_length = max_length
        self.min_length = min_length

        super(CustomStringKeyType, self).__init__(**kwargs)

    def _mock(self, context=None):
        return random_string(get_value_in(self.min_length, self.max_length))

    def to_primitive(self, value, context=None):
        """
        Return encoded key if we have context.app_data['key'], otherwise normal
        """
        if value is None:
            return None

        key = None

        if context and 'key' in context.app_data:
            key = context.app_data['key']

        if isinstance(value, unicode):
            if not key:
                return value
            else:
                return str(transformationFunction(value, key)).decode('utf-8')

        if isinstance(value, str):
            if not key:
                return value
            else:
                return str(strdec.str_enc(value, key))

        return value


    def to_native(self, value, context=None):

        if isinstance(value, unicode):
            return value

        if isinstance(value, str):
            return value.decode('utf-8')

        if isinstance(value, self.allow_casts):
            if isinstance(value, bytes):
                try:
                    return str(value).decode('utf-8')
                except UnicodeError:
                    raise ConversionError(self.messages['decode'].format(value))
            elif isinstance(value, bool):
                pass
            else:
                return str(value).decode('utf-8')

        raise ConversionError(self.messages['convert'].format(value))


    def validate_length(self, value, context=None):
        length = len(value)
        if self.max_length is not None and length > self.max_length:
            raise ValidationError(self.messages['max_length'])

        if self.min_length is not None and length < self.min_length:
            raise ValidationError(self.messages['min_length'])

    def validate_regex(self, value, context=None):
        if self.regex is not None and self.regex.match(value) is None:
            raise ValidationError(self.messages['regex'])


def transformationFunction(value, key):
    return "{} can now be easily manipulated with call-specific data {}".format(value, key)

```

```
class myObj(Model):
    shouldBeTransformedIfRequired = CustomStringKeyType(required=True)
```

```
obj = myObj()
obj.to_primitive(context={'app_data':{'key':'value'}})
```

Thanks so much for your quick response! `make_list` does indeed work. I had one follow-up question: what's the right way to make something similar work for dictionaries, rather than lists? 

I tried (i) calling the ordinary constructor with `make_list` wrapping the arguments, and (ii) writing my own `make_dict`, but neither of these worked. (I know that `make_dict` should be easy - I guess I'm just missing something.) 

Below is some test code. Thanks again!

```python
import autograd.numpy as np
from autograd import grad 
from autograd.container_types import make_list
from autograd.core import primitive

def objective(y, x):
     return np.sum(np.dot(x["a"], y) + x["b"])

def sgd(f, y, x):
    g = grad(f, argnum=1)
    for i in range(5):
        grad_dict = g(y, x)
        for k in x.keys():
            x[k] = x[k] - 0.1 * grad_dict[k]
    return f(y, x)

def wrapper(y):
    x = {"a": np.random.randn(1, 3), "b": np.random.randn(1)}
    return np.sum(sgd(objective, y, x))

y = np.random.randn(3, 1)
print("Forward works:  " + str(wrapper(y)))
g = grad(wrapper)
print("Backward works: " + str(g(y)))
```

